WITH payload AS (
  SELECT $RISQQ61${"questions":[{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.5","internal_question_no":"07B.005","question_sort_key":7200500.139,"question_text":"Are hazardous areas marked with clearly visible warning signage and are the crew familiar with the special precautions and the risks for those areas?","guide_to_inspection":"During the transfer operation, personnel in the bunkering manifold area shall be limited to essential staff only. All staff engaged\nin duties or working in the vicinity of the operations should wear appropriate personal protective equipment (PPE) and every\nindividual shall wear portable gas detector.\nHazardous area means an area in which an explosive gas atmosphere or a flammable gas or vapour is or may be expected to be\npresent, in quantities such as to require special precautions for the construction, installation and use of electrical apparatus or\nany other equipment that may provide potential sources of ignition. Hazardous areas are divided into zone 0, 1 and 2.\nFor additional information, refer to the IGF Code for the definitions of Zone 0,1 and 2.\nHazardous Area Zone 0\nThis zone includes but is not limited to the interiors of fuel tanks, any pipework for pressure relief or other venting systems for\nfuel tanks, pipes and equipment containing fuel.\nHazardous Area Zone 1\nThis zone includes, but is not limited to:\n1. Tank connection spaces, fuel storage hold spaces and intercarrier spaces;\n2. Fuel preparation rooms arranged with ventilation.\n3. Areas on open deck, or semi-enclosed spaces on deck, within 3m of any fuel tank outlet, gas or vapour outlet, bunker manifold\nvalve other fuel valve, fuel pipe flange, fuel preparation room ventilation outlets and fuel tank openings for pressure release\nprovided to permit the flow of small volumes of gas or vapour mixtures caused by thermal variation.\n4. Areas on open deck or semi-enclosed spaces on deck, within 1.5 m of fuel preparation room entrances, fuel preparation room\nventilation inlets and other openings into zone1 spaces.\n5. Areas on the open deck within spillage coamings surrounding gas bunker manifold valves and 3m beyond these, up to a\nheight of 2.4 m above the deck.\n6. Enclosed or semi-enclosed spaces in which pipes containing fuel are located, e.g. ducts around fuel pipes, semi-enclosed\nbunkering stations;\n7. The emergency shutdown (ESD)-protected machinery space is considered a non-hazardous area during normal operation,\nbut any equipment which will need to be operated there following detection of gas leakage must be certified as suitable for\nzone 1;\n8. A space protected by an airlock is considered as a non-hazardous area during normal operation but any equipment which will\nneed to be operated there following detection of gas leakage must be certified as suitable for zone1;\n9. Except for type C tanks, an area within 2.4 m of the outer surface of a fuel containment system where such surface is exposed\nto weather.\nHazardous Area Zone 2\nThis zone includes but is not limited to areas within 1.5 m surrounding open or semi-enclosed spaces of zone 1.\nSpaces containing a bolted hatch to a tank connection space.\n(IGF Code 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":90,"source_page_end":90,"raw_source_text":"Are hazardous areas marked with clearly visible warning signage and are the crew familiar with the special\nprecautions and the risks for those areas? (V)\nGuide to Inspection\nDuring the transfer operation, personnel in the bunkering manifold area shall be limited to essential staff only. All staff engaged\nin duties or working in the vicinity of the operations should wear appropriate personal protective equipment (PPE) and every\nindividual shall wear portable gas detector.\nHazardous area means an area in which an explosive gas atmosphere or a flammable gas or vapour is or may be expected to be\npresent, in quantities such as to require special precautions for the construction, installation and use of electrical apparatus or\nany other equipment that may provide potential sources of ignition. Hazardous areas are divided into zone 0, 1 and 2.\nFor additional information, refer to the IGF Code for the definitions of Zone 0,1 and 2.\nHazardous Area Zone 0\nThis zone includes but is not limited to the interiors of fuel tanks, any pipework for pressure relief or other venting systems for\nfuel tanks, pipes and equipment containing fuel.\nHazardous Area Zone 1\nThis zone includes, but is not limited to:\n1. Tank connection spaces, fuel storage hold spaces and intercarrier spaces;\n2. Fuel preparation rooms arranged with ventilation.\n3. Areas on open deck, or semi-enclosed spaces on deck, within 3m of any fuel tank outlet, gas or vapour outlet, bunker manifold\nvalve other fuel valve, fuel pipe flange, fuel preparation room ventilation outlets and fuel tank openings for pressure release\nprovided to permit the flow of small volumes of gas or vapour mixtures caused by thermal variation.\n4. Areas on open deck or semi-enclosed spaces on deck, within 1.5 m of fuel preparation room entrances, fuel preparation room\nventilation inlets and other openings into zone1 spaces.\n5. Areas on the open deck within spillage coamings surrounding gas bunker manifold valves and 3m beyond these, up to a\nheight of 2.4 m above the deck.\n6. Enclosed or semi-enclosed spaces in which pipes containing fuel are located, e.g. ducts around fuel pipes, semi-enclosed\nbunkering stations;\n7. The emergency shutdown (ESD)-protected machinery space is considered a non-hazardous area during normal operation,\nbut any equipment which will need to be operated there following detection of gas leakage must be certified as suitable for\nzone 1;\n8. A space protected by an airlock is considered as a non-hazardous area during normal operation but any equipment which will\nneed to be operated there following detection of gas leakage must be certified as suitable for zone1;\n9. Except for type C tanks, an area within 2.4 m of the outer surface of a fuel containment system where such surface is exposed\nto weather.\nHazardous Area Zone 2\nThis zone includes but is not limited to areas within 1.5 m surrounding open or semi-enclosed spaces of zone 1.\nSpaces containing a bolted hatch to a tank connection space.\n(IGF Code 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.6","internal_question_no":"07B.006","question_sort_key":7200600.14,"question_text":"Are staff responsible for LNG bunkering aware of their responsibilities and actions to be taken in case of malfunction or emergency and are instructions and warning signs clearly posted on site for safe LNG bunkering operation?","guide_to_inspection":"There shall be written detailed instructions for the bunkering process on both ships regarding responsibility and actions\nrequired in case of malfunction or emergency. The instructions are to be quickly available at all times and all personnel involved\nin bunkering operations are to be familiar with the content and location of the instructions. The instructions should cover the\nfollowing areas:\n> Loss of communication or control system (ESD)\n> Loss of power\n> Safe break-away of ships in case of fire\n> Handling of cryogenic and petroleum products including use of personal protection equipment, ice formation and\nawareness of sharp edges.\n> Waves and weather conditions\nThere shall be warning, and instruction signs posted around hazardous area on both ships. The signs are to\nbe clearly visible and placed according to an accepted guideline for placement of warning signs. The warning\nsigns are to cover the risks of handling cryogenic liquid, fire and safety issues and show restricted areas.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":91,"source_page_end":91,"raw_source_text":"Are staff responsible for LNG bunkering aware of their responsibilities and actions to be taken in case of\nmalfunction or emergency and are instructions and warning signs clearly posted on site for safe LNG\nbunkering operation? (V)\nGuide to Inspection\nThere shall be written detailed instructions for the bunkering process on both ships regarding responsibility and actions\nrequired in case of malfunction or emergency. The instructions are to be quickly available at all times and all personnel involved\nin bunkering operations are to be familiar with the content and location of the instructions. The instructions should cover the\nfollowing areas:\n> Loss of communication or control system (ESD)\n> Loss of power\n> Safe break-away of ships in case of fire\n> Handling of cryogenic and petroleum products including use of personal protection equipment, ice formation and\nawareness of sharp edges.\n> Waves and weather conditions\nThere shall be warning, and instruction signs posted around hazardous area on both ships. The signs are to\nbe clearly visible and placed according to an accepted guideline for placement of warning signs. The warning\nsigns are to cover the risks of handling cryogenic liquid, fire and safety issues and show restricted areas.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.7","internal_question_no":"07B.007","question_sort_key":7200700.141,"question_text":"Is the safety zone clearly marked and, have restrictions within the safety zone been enforced and followed?","guide_to_inspection":"Since the receiving ship normally is larger than the bunker ship is it important to have a safety zone above the bunker station\nduring bunkering. The extent of the safety zone should be 10 metres on each side of the bunker station manifold.\nThis safety zone shall be clearly marked and have the following restrictions:\n> No unauthorised persons to be able to access open deck areas directly above the bunker area\n> Warning signs to be posted around the area\n> Access doors to be locked and only to be opened by trained and authorised personnel\n> No overhead crane lifting in this area during bunkering\n> No maintenance work in the area during bunkering\n> No manoeuvring of ship equipment in the area during bunkering\n> Ventilation inlets in the area to be closed during bunkering\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":91,"source_page_end":91,"raw_source_text":"Is the safety zone clearly marked and, have restrictions within the safety zone been enforced and followed? (V)\nGuide to Inspection\nSince the receiving ship normally is larger than the bunker ship is it important to have a safety zone above the bunker station\nduring bunkering. The extent of the safety zone should be 10 metres on each side of the bunker station manifold.\nThis safety zone shall be clearly marked and have the following restrictions:\n> No unauthorised persons to be able to access open deck areas directly above the bunker area\n> Warning signs to be posted around the area\n> Access doors to be locked and only to be opened by trained and authorised personnel\n> No overhead crane lifting in this area during bunkering\n> No maintenance work in the area during bunkering\n> No manoeuvring of ship equipment in the area during bunkering\n> Ventilation inlets in the area to be closed during bunkering\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.8","internal_question_no":"07B.008","question_sort_key":7200800.142,"question_text":"Are the self-igniting lights of lifebuoys located in the hazardous area intrinsically safe?","guide_to_inspection":"Lifebuoy self-igniting lights do not need to be intrinsically safe if located outside of the hazardous area. However, there must be\nstrict controls in place to avoid those non-intrinsically safe lights being misplaced into the hazardous zone. This may include\nhighlighting/marking of those lights or other appropriate means.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":91,"source_page_end":91,"raw_source_text":"Are the self-igniting lights of lifebuoys located in the hazardous area intrinsically safe? (V)\nGuide to Inspection\nLifebuoy self-igniting lights do not need to be intrinsically safe if located outside of the hazardous area. However, there must be\nstrict controls in place to avoid those non-intrinsically safe lights being misplaced into the hazardous zone. This may include\nhighlighting/marking of those lights or other appropriate means.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.9","internal_question_no":"07B.009","question_sort_key":7200900.143,"question_text":"Is the LNG bunkering operator control panel fitted with an earth indicator light to indicate the faulty circuits and is the control panel free of any faulty earth indication during LNG bunkering?","guide_to_inspection":"The main switchboard on the bunker ship and the control panel on the receiving ship are to have earth indicator lights to indicate\nfaulty circuits.\nAny indications of faulty circuits are to be immediately traced and isolated to avoid arcing around the bunker area. The\nbunkering operation is to be suspended in case of faulty earth indication during ongoing transfer.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":91,"source_page_end":91,"raw_source_text":"Is the LNG bunkering operator control panel fitted with an earth indicator light to indicate the faulty circuits\nand is the control panel free of any faulty earth indication during LNG bunkering? (V)\nGuide to Inspection\nThe main switchboard on the bunker ship and the control panel on the receiving ship are to have earth indicator lights to indicate\nfaulty circuits.\nAny indications of faulty circuits are to be immediately traced and isolated to avoid arcing around the bunker area. The\nbunkering operation is to be suspended in case of faulty earth indication during ongoing transfer.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.10","internal_question_no":"07B.010","question_sort_key":7201000.144,"question_text":"Is the main radio aerial earthed and are portable two-way UHF radios approved for use in hazardous areas?","guide_to_inspection":"The ships’ main radio transmissions may cause electrical resonance in insulated parts of some ship fittings such as mast\nstays, and this can cause arcing across deck fittings. Radio aerials should be earthed but can induce arcing if insulators are\ncoated with salt, dirt, or water. The use of ships main radio equipment during transfer operations can be dangerous and should\nbe restricted during the process. The equipment is not to be used if there is á possibility of flammable gas in the vicinity of the\nantenna.\nSatellite communication equipment normally operates at low power levels and is considered to be a low ignition hazard. The\nequipment is not to be used if there is a possibility of flammable gas in the vicinity of the antenna.\nVHF and UHF communications are low voltage operated and are considered to be safe to use. Hand-held VHF or UHF radios are\nconsidered to be intrinsically safe.\nPortable electronic devices such as mobile phones, cameras etc using batteries are not allowed in hazardous areas unless\nthey are intrinsically safe. It is especially important for personnel working in or visiting such areas to be aware of this. Warning/\nnotification signs are to be posted around these areas.\n(LNG bunkering ship to ship procedure, 2020)\nRightship recommends that only intrinsically safe torches and portable two-way UHF radios should be available and used on\nboard every ship covered by the IGF Code.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":92,"source_page_end":92,"raw_source_text":"Is the main radio aerial earthed and are portable two-way UHF radios approved for use in hazardous areas? (V)\nGuide to Inspection\nThe ships’ main radio transmissions may cause electrical resonance in insulated parts of some ship fittings such as mast\nstays, and this can cause arcing across deck fittings. Radio aerials should be earthed but can induce arcing if insulators are\ncoated with salt, dirt, or water. The use of ships main radio equipment during transfer operations can be dangerous and should\nbe restricted during the process. The equipment is not to be used if there is á possibility of flammable gas in the vicinity of the\nantenna.\nSatellite communication equipment normally operates at low power levels and is considered to be a low ignition hazard. The\nequipment is not to be used if there is a possibility of flammable gas in the vicinity of the antenna.\nVHF and UHF communications are low voltage operated and are considered to be safe to use. Hand-held VHF or UHF radios are\nconsidered to be intrinsically safe.\nPortable electronic devices such as mobile phones, cameras etc using batteries are not allowed in hazardous areas unless\nthey are intrinsically safe. It is especially important for personnel working in or visiting such areas to be aware of this. Warning/\nnotification signs are to be posted around these areas.\n(LNG bunkering ship to ship procedure, 2020)\nRightship recommends that only intrinsically safe torches and portable two-way UHF radios should be available and used on\nboard every ship covered by the IGF Code.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.11","internal_question_no":"07B.011","question_sort_key":7201100.145,"question_text":"Has a pre-compatibility assessment and study of the weather and current forecast been carried out prior to confirming the bunkering operation and is there documented evidence of such assessment and study?","guide_to_inspection":"Weather and current forecast for the area are to be studied before commencing bunkering operations. Each Master is\nresponsible for his own ship and bunkering is only allowed when both Masters agree that ambient conditions (like wind and\nweather) are acceptable. Each Master is also responsible for determining restrictions and taking action in case of a sudden\nchange of ambient conditions during a started bunker transfer.\n(LNG bunkering ship to ship procedure, 2020)\nA compatibility assessment of the bunkering facility and receiving ship should be undertaken prior to confirming the bunkering\noperation to identify any aspects that require particular management. The compatibility assessment should be undertaken\nwith the assistance of an appropriate checklist to be completed and agreed by Master(s) and Person in Charge (PIC) prior to\nengaging in the bunkering operation.\nWhere applicable, as a minimum, compatibility of the following equipment and installations should be checked prior to engaging\nfurther in any low flashpoint bunkering operation:\n> Communication system (hardware, software if any and language) between the PIC, ship’s crew and Bunkering Facility\nOrganisation (BFO) personnel\n> ESD system\n> Bunker connection\n> Emergency release system (ERS) or coupling (ERC)\n> Vapour return line\n> Nitrogen lines’ availability and connection\n> Mooring equipment\n> Bunker station location\n> Transfer system sizing and loading on manifold\n> Location of ERS\n> Closure speed of valves\n> Hazard Operability Analysis (HAZOP) results as applicable","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":92,"source_page_end":92,"raw_source_text":"Has a pre-compatibility assessment and study of the weather and current forecast been carried out prior\nto confirming the bunkering operation and is there documented evidence of such assessment and study? (V)\nGuide to Inspection\nWeather and current forecast for the area are to be studied before commencing bunkering operations. Each Master is\nresponsible for his own ship and bunkering is only allowed when both Masters agree that ambient conditions (like wind and\nweather) are acceptable. Each Master is also responsible for determining restrictions and taking action in case of a sudden\nchange of ambient conditions during a started bunker transfer.\n(LNG bunkering ship to ship procedure, 2020)\nA compatibility assessment of the bunkering facility and receiving ship should be undertaken prior to confirming the bunkering\noperation to identify any aspects that require particular management. The compatibility assessment should be undertaken\nwith the assistance of an appropriate checklist to be completed and agreed by Master(s) and Person in Charge (PIC) prior to\nengaging in the bunkering operation.\nWhere applicable, as a minimum, compatibility of the following equipment and installations should be checked prior to engaging\nfurther in any low flashpoint bunkering operation:\n> Communication system (hardware, software if any and language) between the PIC, ship’s crew and Bunkering Facility\nOrganisation (BFO) personnel\n> ESD system\n> Bunker connection\n> Emergency release system (ERS) or coupling (ERC)\n> Vapour return line\n> Nitrogen lines’ availability and connection\n> Mooring equipment\n> Bunker station location\n> Transfer system sizing and loading on manifold\n> Location of ERS\n> Closure speed of valves\n> Hazard Operability Analysis (HAZOP) results as applicable","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.12","internal_question_no":"07B.012","question_sort_key":7201200.146,"question_text":"Is all lighting around the bunker area Ex-rated and does it appear adequate to illuminate the bunker area?","guide_to_inspection":"The bunkering operation is preferably to be conducted during daylight hours. It is necessary to have adequate lighting in case\nof mooring and bunkering operations after daylight hours. The minimum lighting requirements are the bunker ship deck, the\nreceiving ship bunker station, and the mooring bollards. Normal deck-lighting should in most cases be sufficient, but portable\nspotlights or bridge wing spotlights may be useful for night operations. Note that all lights around the bunker area are to be of\nEx- rated.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":92,"source_page_end":92,"raw_source_text":"Is all lighting around the bunker area Ex-rated and does it appear adequate to illuminate the bunker area? (V)\nGuide to Inspection\nThe bunkering operation is preferably to be conducted during daylight hours. It is necessary to have adequate lighting in case\nof mooring and bunkering operations after daylight hours. The minimum lighting requirements are the bunker ship deck, the\nreceiving ship bunker station, and the mooring bollards. Normal deck-lighting should in most cases be sufficient, but portable\nspotlights or bridge wing spotlights may be useful for night operations. Note that all lights around the bunker area are to be of\nEx- rated.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.13","internal_question_no":"07B.013","question_sort_key":7201300.147,"question_text":"Have the key components of the LNG bunkering system been identified, included within the PMS, maintained and where applicable, calibrated as per the manufacturer’s recommendation?","guide_to_inspection":"Key components of the ship’s systems are to be identified with emphasis on safety to avoid leakage and ignition sources in and\naround the bunker areas. These components should have a maintenance and replacement schedule where inspections and\nactions are documented and stored on board. These components shall have redundancy back-up which can start up within a\nshort period of time.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":93,"source_page_end":93,"raw_source_text":"Have the key components of the LNG bunkering system been identified, included within the PMS,\nmaintained and where applicable, calibrated as per the manufacturer’s recommendation? (V)\nGuide to Inspection\nKey components of the ship’s systems are to be identified with emphasis on safety to avoid leakage and ignition sources in and\naround the bunker areas. These components should have a maintenance and replacement schedule where inspections and\nactions are documented and stored on board. These components shall have redundancy back-up which can start up within a\nshort period of time.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.14","internal_question_no":"07B.014","question_sort_key":7201400.148,"question_text":"Is there a procedure for communication failure during LNG bunkering operation and are crew familiar with such a procedure?","guide_to_inspection":"Communication failure during approach: Abort approach and re-establish contact before attempting a new approach.\nCommunication failure during bunker operations: Sound the emergency signal and suspend all operations in progress\nimmediately. Operations shall not be resumed before communication has been re-established.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":93,"source_page_end":93,"raw_source_text":"Is there a procedure for communication failure during LNG bunkering operation and are crew familiar\nwith such a procedure? (V)\nGuide to Inspection\nCommunication failure during approach: Abort approach and re-establish contact before attempting a new approach.\nCommunication failure during bunker operations: Sound the emergency signal and suspend all operations in progress\nimmediately. Operations shall not be resumed before communication has been re-established.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.15","internal_question_no":"07B.015","question_sort_key":7201500.149,"question_text":"Is there an agreed method of tank pressure and temperature control between the delivering and receiving vessels and is there recorded evidence to show that both ships’ combined temperature and pressure range are within the safety limits before commencing LNG bunkering?","guide_to_inspection":"Both ships must check the LNG tanks regarding temperature and pressure prior to bunkering and note this on the pre-transfer\nbunker checklist. If the temperature of the receiving tank is significantly higher than the bunker tank, there will be an initial\nvaporisation when starting to transfer the LNG. This will increase the tank pressure and can trigger the pressure-relief valve to\nopen if the pressure exceeds the set limit. The pressure of both tanks must be reduced prior to the bunkering in case of a high\nreceiving-tank temperature.\nThe bunker ship Master is to confirm that both ships combined temperature and pressure range are within the safety limits\nbefore commencing transfer.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":93,"source_page_end":93,"raw_source_text":"Is there an agreed method of tank pressure and temperature control between the delivering and receiving\nvessels and is there recorded evidence to show that both ships’ combined temperature and pressure range\nare within the safety limits before commencing LNG bunkering? (V)\nGuide to Inspection\nBoth ships must check the LNG tanks regarding temperature and pressure prior to bunkering and note this on the pre-transfer\nbunker checklist. If the temperature of the receiving tank is significantly higher than the bunker tank, there will be an initial\nvaporisation when starting to transfer the LNG. This will increase the tank pressure and can trigger the pressure-relief valve to\nopen if the pressure exceeds the set limit. The pressure of both tanks must be reduced prior to the bunkering in case of a high\nreceiving-tank temperature.\nThe bunker ship Master is to confirm that both ships combined temperature and pressure range are within the safety limits\nbefore commencing transfer.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.16","internal_question_no":"07B.016","question_sort_key":7201600.15,"question_text":"Is there evidence to show that a detailed mooring plan was exchanged between the delivering and receiving vessels and has the Master of the receiving vessel reviewed the type and size of fenders of the delivering vessel?","guide_to_inspection":"The receiving ship should be able to supply, if requested, a sketch with information about placement and number of fairleads\nand mooring bitts and their relative distances to the bunker station. A mooring plan, showing number of lines and fenders and\ntheir locations should be agreed upon before making berth.\nIt is recommended to use pneumatic type main fenders with a diameter of approx. 1 metre. Size and type of secondary fenders\nto be determined due to the design of the bunker ship. All fenders to be approved by class.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":93,"source_page_end":93,"raw_source_text":"Is there evidence to show that a detailed mooring plan was exchanged between the delivering and\nreceiving vessels and has the Master of the receiving vessel reviewed the type and size of fenders\nof the delivering vessel? (V)\nGuide to Inspection\nThe receiving ship should be able to supply, if requested, a sketch with information about placement and number of fairleads\nand mooring bitts and their relative distances to the bunker station. A mooring plan, showing number of lines and fenders and\ntheir locations should be agreed upon before making berth.\nIt is recommended to use pneumatic type main fenders with a diameter of approx. 1 metre. Size and type of secondary fenders\nto be determined due to the design of the bunker ship. All fenders to be approved by class.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.17","internal_question_no":"07B.017","question_sort_key":7201700.151,"question_text":"Has the LNG hose handling operation been carried out and supervised by trained personnel?","guide_to_inspection":"Dedicated bunker ships may be fitted with specialised hose-handling equipment, but a rather common method is to use a hose\ncrane to deliver bunker hoses from the bunker ship to the receiving ship.\nThe hoses are to be supported to the receiving ship, disconnected from the hose crane, and connected to the manifold, by\ntrained personnel from the receiving ship, before the operation commences.\nEach manifold is to be earthed and the receiving ship shall be equipped with an insulating flange near the coupling to prevent\na possible ignition source due to electrostatic build-up. The hoses with couplings should not touch any un-earthed part before\nconnection to avoid possible electrical arcing.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":94,"source_page_end":94,"raw_source_text":"Has the LNG hose handling operation been carried out and supervised by trained personnel? (V)\nGuide to Inspection\nDedicated bunker ships may be fitted with specialised hose-handling equipment, but a rather common method is to use a hose\ncrane to deliver bunker hoses from the bunker ship to the receiving ship.\nThe hoses are to be supported to the receiving ship, disconnected from the hose crane, and connected to the manifold, by\ntrained personnel from the receiving ship, before the operation commences.\nEach manifold is to be earthed and the receiving ship shall be equipped with an insulating flange near the coupling to prevent\na possible ignition source due to electrostatic build-up. The hoses with couplings should not touch any un-earthed part before\nconnection to avoid possible electrical arcing.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.18","internal_question_no":"07B.018","question_sort_key":7201800.152,"question_text":"Is a water curtain system provided for the ship’s sides in way of manifold and is the manifold tray arrangement adequate and free of any sharp edges?","guide_to_inspection":"There shall not be any sharp edges in the hose handling area. If the receiving vessel has on-board traffic in the vicinity of the\nbunker station, there should be reinforcements built-in to protect the equipment from traffic impact.\nBoth ships must have insulated stainless steel trays, below the LNG and vapour-return manifolds, to prevent damage to the\nsteel hull in case of leakage. The cold LNG liquid causes brittle fractions contacting mild steel. Each tray should have an outlet\noverboard which can be a temporary fitted pipe or hose to lead a possible spill to the water without contact to the hull.\n(LNG bunkering Ship to Ship procedure, 2020)\nFor cargo temperatures below -110°C, a water distribution system shall be fitted in way of the hull under the shore connections\nto provide a low-pressure water curtain for additional protection of the hull steel and the ship’s side structure. This system is in\naddition to the requirements of 11.3.1.4 and shall be operated when cargo transfer is in progress.\n(International code for the construction and equipment of ships carrying liquefied gases in bulk, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":94,"source_page_end":94,"raw_source_text":"Is a water curtain system provided for the ship’s sides in way of manifold and is the manifold\ntray arrangement adequate and free of any sharp edges? (V)\nGuide to Inspection\nThere shall not be any sharp edges in the hose handling area. If the receiving vessel has on-board traffic in the vicinity of the\nbunker station, there should be reinforcements built-in to protect the equipment from traffic impact.\nBoth ships must have insulated stainless steel trays, below the LNG and vapour-return manifolds, to prevent damage to the\nsteel hull in case of leakage. The cold LNG liquid causes brittle fractions contacting mild steel. Each tray should have an outlet\noverboard which can be a temporary fitted pipe or hose to lead a possible spill to the water without contact to the hull.\n(LNG bunkering Ship to Ship procedure, 2020)\nFor cargo temperatures below -110°C, a water distribution system shall be fitted in way of the hull under the shore connections\nto provide a low-pressure water curtain for additional protection of the hull steel and the ship’s side structure. This system is in\naddition to the requirements of 11.3.1.4 and shall be operated when cargo transfer is in progress.\n(International code for the construction and equipment of ships carrying liquefied gases in bulk, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.19","internal_question_no":"07B.019","question_sort_key":7201900.153,"question_text":"Has the LNG fuels bunkering checklist been correctly completed and is there evidence to show that they are effectively managing their obligations as accepted in the checklist?","guide_to_inspection":"The pre-transfer bunker checklist is to be filled out, signed by the responsible operator on the receiving ship and returned to the\nbunker ship before starting any transfer. The signed checklist is to be kept on board the bunker vessel for 3 months. No bunker\noperation is to begin until this checklist is signed and returned to the bunker ship.\n(LNG bunkering ship to ship procedure, 2020)\nISO 20519:2017(E) and the International Association of Ports and Harbors (IAPH) have developed three bunkering checklists for\nLNG bunkering.\nFor additional information, refer to the IAPH website (Click Here).","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":94,"source_page_end":94,"raw_source_text":"Has the LNG fuels bunkering checklist been correctly completed and is there evidence to show that they\nare effectively managing their obligations as accepted in the checklist? (V)\nGuide to Inspection\nThe pre-transfer bunker checklist is to be filled out, signed by the responsible operator on the receiving ship and returned to the\nbunker ship before starting any transfer. The signed checklist is to be kept on board the bunker vessel for 3 months. No bunker\noperation is to begin until this checklist is signed and returned to the bunker ship.\n(LNG bunkering ship to ship procedure, 2020)\nISO 20519:2017(E) and the International Association of Ports and Harbors (IAPH) have developed three bunkering checklists for\nLNG bunkering.\nFor additional information, refer to the IAPH website (Click Here).","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.20","internal_question_no":"07B.020","question_sort_key":7202000.154,"question_text":"Are LNG bunker lines being inerted immediately after completion of LNG bunkering and disconnection of hoses from the manifolds and before departure?","guide_to_inspection":"The receiving ship must inert the bunker lines before departure, which means that the inerting sequence is to start as soon as\nthe hoses are disconnected from the manifold and run until lines are gas free.\nThere shall be a system for gaseous nitrogen onboard the ships. This is needed for purging the piping system from LNG and\nnatural gas after bunkering (inerting). The manually operated valves, which will introduce nitrogen to the LNG system, are\nlocated in the bunker stations.\nIf liquefied gas is trapped in a pipe between two valves or a tank without an exit, the pressure in the tank or pipe will rise until the\npipe or tank bursts. The consequence can be severe injury to personnel. All pipe sections and tanks must therefore be secured\nwith thermal relief valves.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":94,"source_page_end":94,"raw_source_text":"Are LNG bunker lines being inerted immediately after completion of LNG bunkering and disconnection\nof hoses from the manifolds and before departure? (V)\nGuide to Inspection\nThe receiving ship must inert the bunker lines before departure, which means that the inerting sequence is to start as soon as\nthe hoses are disconnected from the manifold and run until lines are gas free.\nThere shall be a system for gaseous nitrogen onboard the ships. This is needed for purging the piping system from LNG and\nnatural gas after bunkering (inerting). The manually operated valves, which will introduce nitrogen to the LNG system, are\nlocated in the bunker stations.\nIf liquefied gas is trapped in a pipe between two valves or a tank without an exit, the pressure in the tank or pipe will rise until the\npipe or tank bursts. The consequence can be severe injury to personnel. All pipe sections and tanks must therefore be secured\nwith thermal relief valves.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.21","internal_question_no":"07B.021","question_sort_key":7202100.155,"question_text":"Are system safety valves in good order and officers aware of the requirements?","guide_to_inspection":"The system includes valves regarded as ordinary safety relief valves as well as so called thermal relief valves. The tanks’ main\nsafety valves are designed to meet the requirements for a LNG tank. Thermal relief valves are designed to meet capacities in a\ntrapped volume in pipes. A safety valve exhausts/vents to a vent mast.\nTo ensure that both safety valves to the LNG tanks are not out of operation at the same time, the safety valve system\nincorporates an “interlock system”. The interlock system consists of lockable valves and a set of keys that permits only one of\nthe safety valves on each tank to be closed.\nIt will be possible to divert gas from different parts of the system to the atmosphere through a vent mast. The LNG tanks’ safety\nvalves will also exhaust to this vent mast, as well as the nitrogen used for purging.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":95,"source_page_end":95,"raw_source_text":"Are system safety valves in good order and officers aware of the requirements? (V)\nGuide to Inspection\nThe system includes valves regarded as ordinary safety relief valves as well as so called thermal relief valves. The tanks’ main\nsafety valves are designed to meet the requirements for a LNG tank. Thermal relief valves are designed to meet capacities in a\ntrapped volume in pipes. A safety valve exhausts/vents to a vent mast.\nTo ensure that both safety valves to the LNG tanks are not out of operation at the same time, the safety valve system\nincorporates an “interlock system”. The interlock system consists of lockable valves and a set of keys that permits only one of\nthe safety valves on each tank to be closed.\nIt will be possible to divert gas from different parts of the system to the atmosphere through a vent mast. The LNG tanks’ safety\nvalves will also exhaust to this vent mast, as well as the nitrogen used for purging.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.22","internal_question_no":"07B.022","question_sort_key":7202200.156,"question_text":"Is the receiving vessel in a high state of readiness at all times during LNG bunkering operations?","guide_to_inspection":"Both ships are to be in a high state of readiness at all times during bunkering operations. The following arrangements should be\nmade on both ships:\n> ESD-system tested and in operation mode\n> Emergency stop box (or Link) led from bunker ship to receiving ship\n> Fire-fighting equipment made ready for immediate use\n> Ships prepared to disconnect hoses at short notice\n> Axes placed at bunker ship mooring stations for quick release of mooring lines\n> Soft rope mooring lines (or tails) are being used for easier emergency cutting\n> Ships have main engines ready for immediate use\n> Outlet from LNG spill trays are led overboard and away from hull.\nIt is possible to have a water curtain system which, in an emergency, sprays water over the ship’s sides around the bunker\nstations to protect the hulls from direct LNG contact, if in place, it should be ready to use.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":95,"source_page_end":95,"raw_source_text":"Is the receiving vessel in a high state of readiness at all times during LNG bunkering operations? (V)\nGuide to Inspection\nBoth ships are to be in a high state of readiness at all times during bunkering operations. The following arrangements should be\nmade on both ships:\n> ESD-system tested and in operation mode\n> Emergency stop box (or Link) led from bunker ship to receiving ship\n> Fire-fighting equipment made ready for immediate use\n> Ships prepared to disconnect hoses at short notice\n> Axes placed at bunker ship mooring stations for quick release of mooring lines\n> Soft rope mooring lines (or tails) are being used for easier emergency cutting\n> Ships have main engines ready for immediate use\n> Outlet from LNG spill trays are led overboard and away from hull.\nIt is possible to have a water curtain system which, in an emergency, sprays water over the ship’s sides around the bunker\nstations to protect the hulls from direct LNG contact, if in place, it should be ready to use.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.23","internal_question_no":"07B.023","question_sort_key":7202300.157,"question_text":"Was the vessel provided with contingency plans for dealing with emergencies?","guide_to_inspection":"Due to the risk of accidents and the potential consequences, it is required that each ship has contingency plans for dealing with\nemergencies. A contingency plan is a summary of individual emergency procedures and shows emergency duties for all ship\npersonnel and plans for taking care of passengers. The contingency plans should be integrated with port and local authorities\nand agreed upon between both ships prior to commencing operations.\nThe following emergencies are example of sections in the contingency plan:\n> Fire on either ship\n> LNG leakage\n> Hose failure\n> Hose quick release arrangements\n> Mooring line failure\n> Communication failure\n> Personnel injuries (frost burns, suffocation etc.)\n> Emergency departure procedure\n> Oil pollution from additional petroleum bunkering\n> Fender burst\n> These potential emergencies are to be evaluated to see if some of the risk scenarios are more likely to occur; if so, they\nshould be included in the contingency plan.\n(LNG bunkering ship to ship procedure, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":95,"source_page_end":95,"raw_source_text":"Was the vessel provided with contingency plans for dealing with emergencies? (V)\nGuide to Inspection\nDue to the risk of accidents and the potential consequences, it is required that each ship has contingency plans for dealing with\nemergencies. A contingency plan is a summary of individual emergency procedures and shows emergency duties for all ship\npersonnel and plans for taking care of passengers. The contingency plans should be integrated with port and local authorities\nand agreed upon between both ships prior to commencing operations.\nThe following emergencies are example of sections in the contingency plan:\n> Fire on either ship\n> LNG leakage\n> Hose failure\n> Hose quick release arrangements\n> Mooring line failure\n> Communication failure\n> Personnel injuries (frost burns, suffocation etc.)\n> Emergency departure procedure\n> Oil pollution from additional petroleum bunkering\n> Fender burst\n> These potential emergencies are to be evaluated to see if some of the risk scenarios are more likely to occur; if so, they\nshould be included in the contingency plan.\n(LNG bunkering ship to ship procedure, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.24","internal_question_no":"07B.024","question_sort_key":7202400.158,"question_text":"Is the emergency shutdown system in good order and is there recorded evidence of regular testing?","guide_to_inspection":"The bunker ship should preferably provide an emergency stop to the receiving ship in order for both ships to be able to stop the\npumps.(LNG bunkering ship to ship procedure, 2020)\nThe bunkering facility and receiving ship should both test their emergency shutdown (ESD) systems not more than 24 hours\nbefore bunkering operations commence. These tests should be documented in accordance with the bunkering procedure\nmanual. The time taken for emergency shutdown valves to move from open to closed, and from closed to open, should be\nchecked regularly and documented.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":96,"source_page_end":96,"raw_source_text":"Is the emergency shutdown system in good order and is there recorded evidence of regular testing? (V)\nGuide to Inspection\nThe bunker ship should preferably provide an emergency stop to the receiving ship in order for both ships to be able to stop the\npumps.(LNG bunkering ship to ship procedure, 2020)\nThe bunkering facility and receiving ship should both test their emergency shutdown (ESD) systems not more than 24 hours\nbefore bunkering operations commence. These tests should be documented in accordance with the bunkering procedure\nmanual. The time taken for emergency shutdown valves to move from open to closed, and from closed to open, should be\nchecked regularly and documented.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.25","internal_question_no":"07B.025","question_sort_key":7202500.159,"question_text":"Are tank domes, domes’ insulation, vapour and filling pipes’ insulation, manhole cover insulation and associated fittings in good order, free from leaks and corrosion?","guide_to_inspection":"The main purposes of the insulation system are to:\n> Minimize loss of boil-off rate of fuel gas (LNG) by restricting heat ingress.\n> Protect the hull structure against harmful temperature fluctuations and absolute temperatures.\n> Minimize condensation or forming of ice on the cold surfaces and thereby reduce accumulation of water and moisture in\nthe cargo containment system.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":96,"source_page_end":96,"raw_source_text":"Are tank domes, domes’ insulation, vapour and filling pipes’ insulation, manhole cover insulation\nand associated fittings in good order, free from leaks and corrosion? (V)\nGuide to Inspection\nThe main purposes of the insulation system are to:\n> Minimize loss of boil-off rate of fuel gas (LNG) by restricting heat ingress.\n> Protect the hull structure against harmful temperature fluctuations and absolute temperatures.\n> Minimize condensation or forming of ice on the cold surfaces and thereby reduce accumulation of water and moisture in\nthe cargo containment system.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.26","internal_question_no":"07B.026","question_sort_key":7202600.16,"question_text":"Are LNG fuel tanks protected by an independent LNG tank level alarm device and is there recorded evidence to show that the device has been tested regularly?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":96,"source_page_end":96,"raw_source_text":"Are LNG fuel tanks protected by an independent LNG tank level alarm device and is there recorded evidence\nto show that the device has been tested regularly? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.27","internal_question_no":"07B.027","question_sort_key":7202700.161,"question_text":"Is there recorded evidence of regular calibration of thermometers, pressure gauges, the gas detection system and tank level gauges?","guide_to_inspection":"Instruments shall be tested to ensure reliability under working conditions and recalibrated at regular intervals. Test procedures\nfor instruments and the intervals between recalibration shall be in accordance with manufacturers’ recommendations.\n(International code for the construction and equipment of ships carrying liquefied gases in bulk, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":96,"source_page_end":96,"raw_source_text":"Is there recorded evidence of regular calibration of thermometers, pressure gauges, the gas detection system\nand tank level gauges? (V)\nGuide to Inspection\nInstruments shall be tested to ensure reliability under working conditions and recalibrated at regular intervals. Test procedures\nfor instruments and the intervals between recalibration shall be in accordance with manufacturers’ recommendations.\n(International code for the construction and equipment of ships carrying liquefied gases in bulk, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.28","internal_question_no":"07B.028","question_sort_key":7202800.162,"question_text":"Is prevention of over-pressurization of the LNG transfer system in the event of activation of the ERS or the ESD documented in the LNG fuel-handing manual?","guide_to_inspection":"Select N/A if the transfer system is designed to consider over pressurization due to surge pressure in the event the ERS or the\nESD is activated.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":96,"source_page_end":96,"raw_source_text":"Is prevention of over-pressurization of the LNG transfer system in the event of activation of the\nERS or the ESD documented in the LNG fuel-handing manual? (V)\nGuide to Inspection\nSelect N/A if the transfer system is designed to consider over pressurization due to surge pressure in the event the ERS or the\nESD is activated.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.29","internal_question_no":"07B.029","question_sort_key":7202900.163,"question_text":"Are precautions to prevent electrostatic charge in the LNG bunker hose being taken and, have the minimum and maximum hose lengths and diameters that the hose support loading arm and/or hose saddles can support been documented in the LNG fuel-handing manual?","guide_to_inspection":"To prevent arcing between the ships the manifolds on both ships are to be earthed, all hoses are to be electrically continuous,\nand each hose string shall be fitted with an insulating flange on the bunker ship manifold. It is important that the insulating\nflange is only fitted to one ship; otherwise, there may be an electrostatic build-up in the hose between the insulating flanges\nwhich can result in arcing.\nElectrical Arcing\nOther places (besides hose connections) where arcing can occur are:\n> Mooring lines (should be insulated)\n> Ladders or gangways between ships (should be insulated)\n> Crane wire runners and hooks (operate carefully)\n> Bare wires and chains for fender support (should be insulated)\n(LNG bunkering Ship to Ship procedure, 2020)\nHose support loading arm and hose supports (saddles), if used, shall conform to ISO 16904 or EN 1474-3 and be designed\nto safely support the loads (static and dynamic) imposed by the LNG transfer operations during hose connection, transfer\noperations and when the hose is disconnected under emergency conditions. They shall provide the necessary support so that\nthe hose bending radius is not below recommended minimum bending radius specified by the hose manufacturer.\nThe minimum and maximum hose lengths and diameters that the hose-support loading arm and/or hose saddles can support\nshall be documented in the LNG bunkering procedures manual.\n(ISO 20519:2017, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":97,"source_page_end":97,"raw_source_text":"Are precautions to prevent electrostatic charge in the LNG bunker hose being taken and, have the\nminimum and maximum hose lengths and diameters that the hose support loading arm and/or hose\nsaddles can support been documented in the LNG fuel-handing manual? (V)\nGuide to Inspection\nTo prevent arcing between the ships the manifolds on both ships are to be earthed, all hoses are to be electrically continuous,\nand each hose string shall be fitted with an insulating flange on the bunker ship manifold. It is important that the insulating\nflange is only fitted to one ship; otherwise, there may be an electrostatic build-up in the hose between the insulating flanges\nwhich can result in arcing.\nElectrical Arcing\nOther places (besides hose connections) where arcing can occur are:\n> Mooring lines (should be insulated)\n> Ladders or gangways between ships (should be insulated)\n> Crane wire runners and hooks (operate carefully)\n> Bare wires and chains for fender support (should be insulated)\n(LNG bunkering Ship to Ship procedure, 2020)\nHose support loading arm and hose supports (saddles), if used, shall conform to ISO 16904 or EN 1474-3 and be designed\nto safely support the loads (static and dynamic) imposed by the LNG transfer operations during hose connection, transfer\noperations and when the hose is disconnected under emergency conditions. They shall provide the necessary support so that\nthe hose bending radius is not below recommended minimum bending radius specified by the hose manufacturer.\nThe minimum and maximum hose lengths and diameters that the hose-support loading arm and/or hose saddles can support\nshall be documented in the LNG bunkering procedures manual.\n(ISO 20519:2017, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.30","internal_question_no":"07B.030","question_sort_key":7203000.164,"question_text":"Are the officers aware of any LNG bunker loading limitations for the vessel and are these limitations, if applicable, clearly posted at the LNG bunker operation panel?","guide_to_inspection":"A document shall be provided to the ship, specifying the maximum allowable loading limits for each cargo tank and product, at\neach applicable loading temperature and maximum reference temperature. The information in this document shall be approved\nby the administration or recognised organisation acting on its behalf. The pressure at which the pressure relief valves (PRVs)\nhave been set shall also be stated in the document. A copy of the document shall be permanently kept on board by the Master.\n(International code for the construction and equipment of ships carrying liquefied gases in bulk, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":97,"source_page_end":97,"raw_source_text":"Are the officers aware of any LNG bunker loading limitations for the vessel and are these limitations,\nif applicable, clearly posted at the LNG bunker operation panel? (V)\nGuide to Inspection\nA document shall be provided to the ship, specifying the maximum allowable loading limits for each cargo tank and product, at\neach applicable loading temperature and maximum reference temperature. The information in this document shall be approved\nby the administration or recognised organisation acting on its behalf. The pressure at which the pressure relief valves (PRVs)\nhave been set shall also be stated in the document. A copy of the document shall be permanently kept on board by the Master.\n(International code for the construction and equipment of ships carrying liquefied gases in bulk, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.1","internal_question_no":"07C.001","question_sort_key":7300100.165,"question_text":"Has a Certificate or Statement of Compliance been issued by Class to confirm the safe use of Methyl/Ethyl Alcohol as fuel by the vessel?","guide_to_inspection":"According to the SOLAS Convention, specifically Chapter II-1, Regulations 56 and 57, ships using methanol as fuel shall adhere\nto the ‘International Code of Safety for Ships Using Gases or Other Low-Flashpoint Fuels’, also referred to as the IGF Code. It’s\nimportant to note that the IGF Code does not provide specific safety requirements for the use of methanol as a fuel. At present,\nthe requirements are confined to the ‘Interim Guideline for the Safety of Ships Using Methyl/Ethyl Alcohol as Fuel’ (MSC.1/Circ.\n1621), which was issued by the IMO. The mandatory safety requirements for this scenario have yet to be defined by international\nconventions. Please CLICK HERE to access MSC.1/Circ. 1621.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":97,"source_page_end":97,"raw_source_text":"Has a Certificate or Statement of Compliance been issued by Class to confirm the safe use of Methyl/Ethyl\nAlcohol as fuel by the vessel? (V)\nGuide to Inspection\nAccording to the SOLAS Convention, specifically Chapter II-1, Regulations 56 and 57, ships using methanol as fuel shall adhere\nto the ‘International Code of Safety for Ships Using Gases or Other Low-Flashpoint Fuels’, also referred to as the IGF Code. It’s\nimportant to note that the IGF Code does not provide specific safety requirements for the use of methanol as a fuel. At present,\nthe requirements are confined to the ‘Interim Guideline for the Safety of Ships Using Methyl/Ethyl Alcohol as Fuel’ (MSC.1/Circ.\n1621), which was issued by the IMO. The mandatory safety requirements for this scenario have yet to be defined by international\nconventions. Please CLICK HERE to access MSC.1/Circ. 1621.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.2","internal_question_no":"07C.002","question_sort_key":7300200.166,"question_text":"Was the vessel provided with a procedure for bunkering Methyl/Ethyl Alcohol and were the Master and officers familiar with its contents?","guide_to_inspection":"A procedure outlining methanol bunkering procedures which may be incorporated in the ship’s fuel handling manual, must be\navailable. It should include:\n> A list of personnel who are currently qualified to conduct methanol bunkering operations, taking into account the specific\nhazards of methyl/ethyl alcohol used as fuel (colourless flame, low flash point, high flammability range).\n> A description of the duties of all personnel involved.\n> A description of the bunkering parameters for which the system has been designed.\n> De-bunkering procedures\n> Identification of safety zone and Simultaneous Operations (SIMOPS) assessment (when applicable)\n> Nitrogen padding of bunker tanks\n> Pressure test and purging of bunker hose (liquid and vapour) with Nitrogen\n> Vapour recovery procedures have been established to prevent operational venting\n> A list of any limitations on bunkering operations identified in the risk assessment or imposed by authorities, such as\nmonitoring and early detection of flame and lightning risk .\n> List of personal protective equipment, firefighting equipment’s, methanol gas detector and thermal cameras.\n> Use and location of Ship Shore Link (SSL) for automatic Emergency Stop Device (ESD) communication with the receiving\nship and the delivering facility ESD system\n> Consider the use of Quick Connect and Disconnect Coupling (QCDC) at the bunkering manifold.\n> Emergency contact information.\n> This procedure can be incorporated into an existing ISM manual, provided it is easily accessible to all personnel involved at\neach transfer site.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":98,"source_page_end":98,"raw_source_text":"Was the vessel provided with a procedure for bunkering Methyl/Ethyl Alcohol and were the Master and\nofficers familiar with its contents?(V)\nGuide to Inspection\nA procedure outlining methanol bunkering procedures which may be incorporated in the ship’s fuel handling manual, must be\navailable. It should include:\n> A list of personnel who are currently qualified to conduct methanol bunkering operations, taking into account the specific\nhazards of methyl/ethyl alcohol used as fuel (colourless flame, low flash point, high flammability range).\n> A description of the duties of all personnel involved.\n> A description of the bunkering parameters for which the system has been designed.\n> De-bunkering procedures\n> Identification of safety zone and Simultaneous Operations (SIMOPS) assessment (when applicable)\n> Nitrogen padding of bunker tanks\n> Pressure test and purging of bunker hose (liquid and vapour) with Nitrogen\n> Vapour recovery procedures have been established to prevent operational venting\n> A list of any limitations on bunkering operations identified in the risk assessment or imposed by authorities, such as\nmonitoring and early detection of flame and lightning risk .\n> List of personal protective equipment, firefighting equipment’s, methanol gas detector and thermal cameras.\n> Use and location of Ship Shore Link (SSL) for automatic Emergency Stop Device (ESD) communication with the receiving\nship and the delivering facility ESD system\n> Consider the use of Quick Connect and Disconnect Coupling (QCDC) at the bunkering manifold.\n> Emergency contact information.\n> This procedure can be incorporated into an existing ISM manual, provided it is easily accessible to all personnel involved at\neach transfer site.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.3","internal_question_no":"07C.003","question_sort_key":7300300.167,"question_text":"Were the Master, officers, and ratings suitably trained and qualified to serve on board a ship using methylene/ethyl alcohol fuels?","guide_to_inspection":"The company should ensure that seafarers on board ships using methyl/ethyl alcohol fuels have completed specific training to\nattain the abilities that are appropriate to the capacity to be filled, and duties and responsibilities to be taken up.\nThe master, officers, ratings and other personnel on ships using methyl/ethyl alcohol fuels should be trained and qualified in\naccordance with regulation V/3 of the STCW Convention and section A-V/3 of the STCW Code, taking into account the specific\nhazards of methyl/ethyl alcohol used as fuel.\n(MSC.1/Circ.1621 2020)\nMethanol and Methyl/ethyl alcohol fuel-related drills and exercises should be incorporated into the company’s SMS including\nschedule for periodical drills.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":98,"source_page_end":98,"raw_source_text":"Were the Master, officers, and ratings suitably trained and qualified to serve on board a ship using\nmethylene/ethyl alcohol fuels?(V)\nGuide to Inspection\nThe company should ensure that seafarers on board ships using methyl/ethyl alcohol fuels have completed specific training to\nattain the abilities that are appropriate to the capacity to be filled, and duties and responsibilities to be taken up.\nThe master, officers, ratings and other personnel on ships using methyl/ethyl alcohol fuels should be trained and qualified in\naccordance with regulation V/3 of the STCW Convention and section A-V/3 of the STCW Code, taking into account the specific\nhazards of methyl/ethyl alcohol used as fuel.\n(MSC.1/Circ.1621 2020)\nMethanol and Methyl/ethyl alcohol fuel-related drills and exercises should be incorporated into the company’s SMS including\nschedule for periodical drills.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.4","internal_question_no":"07C.004","question_sort_key":7300400.168,"question_text":"Is a suitable firefighting system in place for using methyl/ethyl alcohol as fuel, and were the crew members familiar with the location, purpose, and its operation?","guide_to_inspection":"Where fuel tanks were located on open deck, there should be a fixed fire-fighting system of alcohol-resistant foam type, as set\nout in chapter 17 of the IBC Code and, where appropriate, chapter 14 of the FSS Code.\nThe alcohol-resistant foam type fire-fighting system should cover the area below the fuel tank where a spill of fuel could be\nexpected to spread.\nThe bunker station should have a fixed fire-extinguishing system of alcohol resistant foam type and a portable dry chemical\npowder extinguisher or an equivalent extinguisher, located near the entrance of the bunkering station.\nMachinery space and fuel preparation space where methyl/ethyl alcohol-fueled engines or fuel pumps are arranged should be\nprotected by an approved fixed fire-extinguishing system in accordance with SOLAS regulation II-2/10 and the FSS Code. In\naddition, the fire-extinguishing medium used should be suitable for the extinguishing of methyl/ethyl alcohol fires.\nAn approved alcohol-resistant foam system covering the tank top and bilge area under the floor plates should be arranged for\nmachinery space category A and fuel preparation space containing methyl/ethyl alcohol.\n(MSC.1/Circ.1621 2020)\nThe ship’s fuel handling manual should incorporate the fire-fighting and emergency procedures: operation and maintenance of\nfire-fighting systems and use of extinguishing agents.\nFlammable vapors burn over a methanol pool, and the liquid evaporates due to the heat, contributing to the burn.\nTherefore, the most effective ways of fighting a methanol fire are to smother the vapors or to dilute the flammable substances\nbelow their lower flammable limit.\nPortable dry chemical or CO2 extinguishers can be used for small methanol fires where there is less risk of methanol pool\nevaporation. For larger volumes of methanol, water extinguishers may be used, if the volume of water is at least four times\nthe size of the methanol pool. Alcohol Resistant Film Forming Foam (AR-FFF) extinguishers with foam water proportioning\nequipment are a highly recommended method for large methanol pool fires, such as a potential fire below methanol fuel tanks.\n(Sustainability whitepaper Methanol as marine fuel 2021)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":98,"source_page_end":99,"raw_source_text":"Is a suitable firefighting system in place for using methyl/ethyl alcohol as fuel, and were the crew members\nfamiliar with the location, purpose, and its operation?(V)\nGuide to Inspection\nWhere fuel tanks were located on open deck, there should be a fixed fire-fighting system of alcohol-resistant foam type, as set\nout in chapter 17 of the IBC Code and, where appropriate, chapter 14 of the FSS Code.\nThe alcohol-resistant foam type fire-fighting system should cover the area below the fuel tank where a spill of fuel could be\nexpected to spread.\nThe bunker station should have a fixed fire-extinguishing system of alcohol resistant foam type and a portable dry chemical\npowder extinguisher or an equivalent extinguisher, located near the entrance of the bunkering station.\nMachinery space and fuel preparation space where methyl/ethyl alcohol-fueled engines or fuel pumps are arranged should be\nprotected by an approved fixed fire-extinguishing system in accordance with SOLAS regulation II-2/10 and the FSS Code. In\naddition, the fire-extinguishing medium used should be suitable for the extinguishing of methyl/ethyl alcohol fires.\nAn approved alcohol-resistant foam system covering the tank top and bilge area under the floor plates should be arranged for\nmachinery space category A and fuel preparation space containing methyl/ethyl alcohol.\n(MSC.1/Circ.1621 2020)\nThe ship’s fuel handling manual should incorporate the fire-fighting and emergency procedures: operation and maintenance of\nfire-fighting systems and use of extinguishing agents.\nFlammable vapors burn over a methanol pool, and the liquid evaporates due to the heat, contributing to the burn.\nTherefore, the most effective ways of fighting a methanol fire are to smother the vapors or to dilute the flammable substances\nbelow their lower flammable limit.\nPortable dry chemical or CO2 extinguishers can be used for small methanol fires where there is less risk of methanol pool\nevaporation. For larger volumes of methanol, water extinguishers may be used, if the volume of water is at least four times\nthe size of the methanol pool. Alcohol Resistant Film Forming Foam (AR-FFF) extinguishers with foam water proportioning\nequipment are a highly recommended method for large methanol pool fires, such as a potential fire below methanol fuel tanks.\n(Sustainability whitepaper Methanol as marine fuel 2021)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.5","internal_question_no":"07C.005","question_sort_key":7300500.169,"question_text":"Is the ventilation system in the fuel preparation spaces and bunkering station, when not located on the open deck, adequate, and were the Master, officers, and crew familiar with the ventilation system’s location, purpose, and the procedures for stopping the power ventilation systems from an external location?","guide_to_inspection":"Fuel preparation spaces should be provided with an effective mechanical forced ventilation system of extraction type. During\nnormal operation the ventilation should be at least 30 air changes per hour.\nThe number and power of the ventilation fans should be such that the capacity is not reduced by more than 50% if a fan with a\nseparate circuit from the main switchboard or emergency switchboard or a group of fans with common circuit from the main\nswitchboard or emergency switchboard is inoperable.\nVentilation systems for fuel preparation spaces and other fuel handling spaces should be in operation when pumps or other fuel\ntreatment equipment are working.\nBunkering stations that are not located on open deck should be suitably ventilated to ensure that any vapor being released\nduring bunkering operations will be removed outside. If the natural ventilation is not sufficient, the bunkering stations should be\nsubject to special consideration with respect to provisions for mechanical ventilation. The Administration may require special\nrisk assessment.\nAny loss of the required ventilating capacity should give an audible and visual alarm on the navigation bridge, and in a\ncontinuously manned central control station or safety center as well as locally.\n(MSC.1/Circ.1621 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":99,"source_page_end":99,"raw_source_text":"Is the ventilation system in the fuel preparation spaces and bunkering station, when not located on the\nopen deck, adequate, and were the Master, officers, and crew familiar with the ventilation system’s location,\npurpose, and the procedures for stopping the power ventilation systems from an external location?(V)\nGuide to Inspection\nFuel preparation spaces should be provided with an effective mechanical forced ventilation system of extraction type. During\nnormal operation the ventilation should be at least 30 air changes per hour.\nThe number and power of the ventilation fans should be such that the capacity is not reduced by more than 50% if a fan with a\nseparate circuit from the main switchboard or emergency switchboard or a group of fans with common circuit from the main\nswitchboard or emergency switchboard is inoperable.\nVentilation systems for fuel preparation spaces and other fuel handling spaces should be in operation when pumps or other fuel\ntreatment equipment are working.\nBunkering stations that are not located on open deck should be suitably ventilated to ensure that any vapor being released\nduring bunkering operations will be removed outside. If the natural ventilation is not sufficient, the bunkering stations should be\nsubject to special consideration with respect to provisions for mechanical ventilation. The Administration may require special\nrisk assessment.\nAny loss of the required ventilating capacity should give an audible and visual alarm on the navigation bridge, and in a\ncontinuously manned central control station or safety center as well as locally.\n(MSC.1/Circ.1621 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.6","internal_question_no":"07C.006","question_sort_key":7300600.17,"question_text":"Were the fuel tank level indicators and their overflow control system in good working order, and was there recorded evidence of regular testing?","guide_to_inspection":"Each fuel tank should be fitted with closed level gauging devices, arranged to ensure a level reading is always obtainable and\nunless any necessary maintenance can be carried out while the fuel tank is in service, two devices should be installed.\nEach fuel tank should be fitted with a visual and audible high-level alarm. This should be able to be function tested from the\noutside of the tank and can be common with the level gauging system (configured as an alarm on the gauging transmitter),but\nshould be independent of the high-high-level alarm.\nAn additional sensor (high-high-level) operating independently of the high liquid level alarm should automatically actuate a\nshut-off valve to avoid excessive liquid pressure in the bunkering line and prevent the tank from becoming liquid full.\nThe high and high-high-level alarm for the fuel tanks should be visual and audible at the location at which gas freeing by water\nfilling of the fuel tanks is controlled, given that water filling is the preferred method for gas freeing.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":99,"source_page_end":99,"raw_source_text":"Were the fuel tank level indicators and their overflow control system in good working order, and was there\nrecorded evidence of regular testing?(V)\nGuide to Inspection\nEach fuel tank should be fitted with closed level gauging devices, arranged to ensure a level reading is always obtainable and\nunless any necessary maintenance can be carried out while the fuel tank is in service, two devices should be installed.\nEach fuel tank should be fitted with a visual and audible high-level alarm. This should be able to be function tested from the\noutside of the tank and can be common with the level gauging system (configured as an alarm on the gauging transmitter),but\nshould be independent of the high-high-level alarm.\nAn additional sensor (high-high-level) operating independently of the high liquid level alarm should automatically actuate a\nshut-off valve to avoid excessive liquid pressure in the bunkering line and prevent the tank from becoming liquid full.\nThe high and high-high-level alarm for the fuel tanks should be visual and audible at the location at which gas freeing by water\nfilling of the fuel tanks is controlled, given that water filling is the preferred method for gas freeing.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.7","internal_question_no":"07C.007","question_sort_key":7300700.171,"question_text":"Was the remote control and monitoring system in the bunkering remote control station in good working condition, and was there documented evidence to confirm that regular testing has been conducted?","guide_to_inspection":"Bunkering control should be from a safe remote location. At this safe remote location:\n1. tank level should be capable of being monitored;\n2. The remote-control valves, which are integral to the bunkering Emergency Shutdown (ESD) system, should be operable from\nthis location; closing of the bunkering shutdown valve should be possible from the control location for bunkering and from\nanother safe location; and\n3. overfill alarms and automatic shutdown should also be indicated at this location.\nIf the ventilation in the ducting enclosure or annular spaces of the double walled bunkering lines stops, an audible and visual\nalarm should be activated at the bunkering control location.\nIf fuel leakage is detected in ducting enclosure or the annular spaces of the double walled bunkering lines, an audible and visual\nalarm and emergency shutdown of the bunkering valve should automatically be activated.\nFire detection in machinery space containing methyl/ethyl alcohol engines and fuel storage hold spaces should give audible and\nvisual alarms on the navigation bridge and in a continuously manned central control station or safety center as well as locally.\n(MSC.1/Circ.1621 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":100,"source_page_end":100,"raw_source_text":"Was the remote control and monitoring system in the bunkering remote control station in good working\ncondition, and was there documented evidence to confirm that regular testing has been conducted?(V)\nGuide to Inspection\nBunkering control should be from a safe remote location. At this safe remote location:\n1. tank level should be capable of being monitored;\n2. The remote-control valves, which are integral to the bunkering Emergency Shutdown (ESD) system, should be operable from\nthis location; closing of the bunkering shutdown valve should be possible from the control location for bunkering and from\nanother safe location; and\n3. overfill alarms and automatic shutdown should also be indicated at this location.\nIf the ventilation in the ducting enclosure or annular spaces of the double walled bunkering lines stops, an audible and visual\nalarm should be activated at the bunkering control location.\nIf fuel leakage is detected in ducting enclosure or the annular spaces of the double walled bunkering lines, an audible and visual\nalarm and emergency shutdown of the bunkering valve should automatically be activated.\nFire detection in machinery space containing methyl/ethyl alcohol engines and fuel storage hold spaces should give audible and\nvisual alarms on the navigation bridge and in a continuously manned central control station or safety center as well as locally.\n(MSC.1/Circ.1621 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.8","internal_question_no":"07C.008","question_sort_key":7300800.172,"question_text":"Were safety notices, caution placards and signs prominently displayed and customised for each compartment to underline the safety instructions?","guide_to_inspection":"If the fuel supply is shut off due to activation of an automatic valve, the fuel supply should not be opened until the reason for\nthe disconnection is ascertained and the necessary precautions taken. A readily visible notice giving instructions to this effect\nshould be placed at the operating station for the shut-off valves in the fuel supply lines.\nA caution placard or signboard should be permanently fitted in the machinery space containing methyl/ethyl-fueled engines\nstating that heavy lifting, implying danger of damage to the fuel pipes, should not be done when the engine(s) is running on\nmethyl/ethyl.\n(MSC.1/Circ.1621 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":100,"source_page_end":100,"raw_source_text":"Were safety notices, caution placards and signs prominently displayed and customised for each\ncompartment to underline the safety instructions?(V)\nGuide to Inspection\nIf the fuel supply is shut off due to activation of an automatic valve, the fuel supply should not be opened until the reason for\nthe disconnection is ascertained and the necessary precautions taken. A readily visible notice giving instructions to this effect\nshould be placed at the operating station for the shut-off valves in the fuel supply lines.\nA caution placard or signboard should be permanently fitted in the machinery space containing methyl/ethyl-fueled engines\nstating that heavy lifting, implying danger of damage to the fuel pipes, should not be done when the engine(s) is running on\nmethyl/ethyl.\n(MSC.1/Circ.1621 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.9","internal_question_no":"07C.009","question_sort_key":7300900.173,"question_text":"Were drills and emergency exercises, related to methyl/ethyl alcohol fuels, integrated into the company’s defined emergency drills, and were there available records to show that company-defined emergency drills have been completed and documented as required by company procedures?","guide_to_inspection":"Drills and emergency exercises on board are to be conducted at regular intervals. Exercises related to low flash point fuels, such as\nmethanol are to at least include following:\n1. tabletop exercise.\n2. review of fueling procedures based in the fuel handling manual required by 17.2.3.\n3. responses to potential contingences.\n4. tests of equipment intended for contingency response; and\n5. reviews that assigned seafarers are trained to perform assigned duties during fueling, operation and contingency response.\nMethanol related exercises are to be incorporated into periodical drills required by resolution IMO Resolution A.741(18).\n(MSC.1/Circ.1621 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":100,"source_page_end":100,"raw_source_text":"Were drills and emergency exercises, related to methyl/ethyl alcohol fuels, integrated into the company’s\ndefined emergency drills, and were there available records to show that company-defined emergency drills\nhave been completed and documented as required by company procedures?(V)\nGuide to Inspection\nDrills and emergency exercises on board are to be conducted at regular intervals. Exercises related to low flash point fuels, such as\nmethanol are to at least include following:\n1. tabletop exercise.\n2. review of fueling procedures based in the fuel handling manual required by 17.2.3.\n3. responses to potential contingences.\n4. tests of equipment intended for contingency response; and\n5. reviews that assigned seafarers are trained to perform assigned duties during fueling, operation and contingency response.\nMethanol related exercises are to be incorporated into periodical drills required by resolution IMO Resolution A.741(18).\n(MSC.1/Circ.1621 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.10","internal_question_no":"07C.010","question_sort_key":7301000.174,"question_text":"Were the maintenance and repair procedures inclusive of the fuel containment system, adjacent spaces, and electrical equipment installed in explosion hazardous spaces and areas?","guide_to_inspection":"Maintenance and repair procedures should include considerations with respect to the fuel containment system and adjacent spaces.\nSpecial consideration should be given to the toxicity of fuel.\nThe procedures and information should include maintenance of electrical equipment that is installed in explosion hazardous spaces and\nareas. The inspection and maintenance of electrical installations in explosion hazardous spaces should be performed in accordance\nwith recognised standards.\n(MSC.1/Circ.1621 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":100,"source_page_end":100,"raw_source_text":"Were the maintenance and repair procedures inclusive of the fuel containment system, adjacent spaces,\nand electrical equipment installed in explosion hazardous spaces and areas?(V)\nGuide to Inspection\nMaintenance and repair procedures should include considerations with respect to the fuel containment system and adjacent spaces.\nSpecial consideration should be given to the toxicity of fuel.\nThe procedures and information should include maintenance of electrical equipment that is installed in explosion hazardous spaces and\nareas. The inspection and maintenance of electrical installations in explosion hazardous spaces should be performed in accordance\nwith recognised standards.\n(MSC.1/Circ.1621 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07C","section_number":7,"section_letter":"C","section_title":"Fuel Management (Alternative Fuel- Methanol)","printed_question_no":"7.11","internal_question_no":"07C.011","question_sort_key":7301100.175,"question_text":"Were the officers and ratings familiar with the pre-bunkering verification requirements and the bunker operation safety checklist, and were there records available to demonstrate that the pre-bunkering and bunkering checks were conducted?","guide_to_inspection":"Prior to conducting bunkering operations, pre-bunkering verification including, but not limited to, the following should be carried out and\ndocumented in the bunker safety checklist:\n1. all communications methods, including ship shore link (SSL), if fitted;\n2. operation of fixed fire detection equipment;\n3. operation of portable gas detection equipment;\n4. readiness of fixed and portable fire-fighting systems and appliances;\n5. operation of remote-controlled valves; and\n6. inspection of hoses and couplings.\nDocumentation of successful verification should be indicated by the mutually agreed and executed bunkering safety checklist signed by\nboth PICs.\n(MSC.1/Circ.1621 2020)\nRightShip recommends Ship Managers implement standardised bunker checklists. This initiative aims to minimise confusion that may\nresult from following different rules and regulations at different ports and will likely increase personnel consciousness and familiarity with\nthe standardized checklists contents.It is recommended that the ship be equipped with thermal cameras, lightning detectors, and CCTV\nat the bunkering station for leak and fire prevention. The crew must also be trained in the proper use of such equipment and familiarised\nduring shipboard drills.\nThe International Association of Ports and Harbours (IAPH) has developed checklists for the use of Methanol as fuel in ship-to-ship and\ntruck-to-ship operations. These checklists are readily available for download from their official website.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":101,"source_page_end":101,"raw_source_text":"Were the officers and ratings familiar with the pre-bunkering verification requirements and the bunker\noperation safety checklist, and were there records available to demonstrate that the pre-bunkering and\nbunkering checks were conducted?(V)\nGuide to Inspection\nPrior to conducting bunkering operations, pre-bunkering verification including, but not limited to, the following should be carried out and\ndocumented in the bunker safety checklist:\n1. all communications methods, including ship shore link (SSL), if fitted;\n2. operation of fixed fire detection equipment;\n3. operation of portable gas detection equipment;\n4. readiness of fixed and portable fire-fighting systems and appliances;\n5. operation of remote-controlled valves; and\n6. inspection of hoses and couplings.\nDocumentation of successful verification should be indicated by the mutually agreed and executed bunkering safety checklist signed by\nboth PICs.\n(MSC.1/Circ.1621 2020)\nRightShip recommends Ship Managers implement standardised bunker checklists. This initiative aims to minimise confusion that may\nresult from following different rules and regulations at different ports and will likely increase personnel consciousness and familiarity with\nthe standardized checklists contents.It is recommended that the ship be equipped with thermal cameras, lightning detectors, and CCTV\nat the bunkering station for leak and fire prevention. The crew must also be trained in the proper use of such equipment and familiarised\nduring shipboard drills.\nThe International Association of Ports and Harbours (IAPH) has developed checklists for the use of Methanol as fuel in ship-to-ship and\ntruck-to-ship operations. These checklists are readily available for download from their official website.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.1","internal_question_no":"07D.001","question_sort_key":7400100.176,"question_text":"Does the Ammonia Fuel Bunker Management Plan include procedures for the safe loading, transfer, and storage of ammonia; verification of equipment compatibility; and are the Master and Oficers familiar with safe handlin procedures, loading limits,equipment compatibility, emergency drills and communication protocols?","guide_to_inspection":"Bunker Management for Ammonia-Fuelled Ships\n> Bunker management plan for ammonia-fuelled vessels should address the unique hazards associated with ammonia,\nincluding its toxicity and flammability. The plan should incorporate\n> the following critical elements:\n> Safe Handling Procedures: Procedure for the safe loading, transfer, and storage of ammonia.\n> Loading Limits: Clearly defined loading limits in accordance with the IGF Code.\n> Communication Procedure: Effective communication procedures between ship and shore personnel.\n> Equipment Compatibility: Verification of compatibility between shipboard and shorebased systems.\n6.8 Provisions on loading limit for fuel tanks\n> 6.8.1 Storage tanks for liquefied ammonia should not be filled to more than a volume equivalent to 98% full at the reference\ntemperature as defined in 2.2.36 of the IGF Code.\n> 6.8.2 In cases where the tank insulation and tank location make the probability very small for the tank contents to be\nheated up due to an external fire, special considerations may be made to allow a higher loading limit than calculated using\nthe reference temperature, but never above 95%.\n> (Class NK, 2024)\n> Bunkering procedures, and safety framework are to be developed with reference to the Ammonia Bunkering Management\nPlan (ABMP). Subsequent reviews and amendments in procedures are to be recorded in the ABMP.\n> (The Class NK 2025 Guidelines for the Safe Operation of Ammonia-Fuelled Vessels, Appendix 3)\nSafety Management System Updates for Ammonia Fuel Use\n> The company’s procedures should include fuel-specific operating procedures, maintenance requirements, and emergency\npreparedness measures, including regular drills. These procedures should specifically address residual risks that\ncannot be eliminated but must be mitigated through appropriate control measures. Formal risk assessments should be\nconducted to identify and address potential hazards associated with the use of ammonia as fuel. These assessments\nshould consider risks to personnel onboard, the environment, and the structural integrity of the vessel. Particular emphasis\nshould be placed on hazards related to the vessel’s physical design, layout, operation, and maintenance, including any\nreasonably foreseeable failures. Given the toxicity of ammonia and the potential for its release, thorough evaluation is\nessential to safeguard crew and environmental safety.\nScope of Risk assessment\nThe assessment should cover all relevant aspects of the vessel, focusing on system interactions and\navailable data. Key areas include:\n> Ammonia storage and vapor/pressure management systems\n> Venting and ventilation arrangements\n> Engine room and machinery spaces\n> Ammonia consumption equipment\n> Ammonia fuel supply and return systems\n> (ABS -Safety Insights For Ammonia as a Marine Fuel March 2025)\nRisk assessment\n> 4.2.1 A holistic risk assessment should be conducted to ensure that risks arising from the use of ammonia as fuel a􀆯ectin g\npersons on board, the environment, the structural strength, or the integrity of the ship and its sub-systems are addressed.\nConsideration should be given to the hazards associated with physical layout, operation and maintenance, following any\nreasonably foreseeable failure.\n> 4.2.2 The risk assessment should specifically consider the ammonia system integrity with a focus on its ability to prevent\nand isolate leakages and also evaluate potential toxicity hazards, ignition mechanisms and consequences of ignition.\nSpecial consideration should be given, but not limited to, the following specific ammonia-related hazards and topics:\n> 1- loss of function;\n> 2- component damage;\n> 3- fire;\n> 4- explosion;\n> 5- toxicity; and\n> 6- electric shock\n> 4.2.3 Risks, which cannot be eliminated, should be mitigated as necessary. Details of risks, and the means by\nwhich they are mitigated, should be documented to the satisfaction of the Administration.\n> (MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":101,"source_page_end":102,"raw_source_text":"Does the Ammonia Fuel Bunker Management Plan include procedures for the safe loading, transfer, and\nstorage of ammonia; verification of equipment compatibility; and are the Master and Oficers familiar with\nsafe handlin procedures, loading limits,equipment compatibility, emergency drills and communication protocols? (V)\nGuide to Inspection\nBunker Management for Ammonia-Fuelled Ships\n> Bunker management plan for ammonia-fuelled vessels should address the unique hazards associated with ammonia,\nincluding its toxicity and flammability. The plan should incorporate\n> the following critical elements:\n> Safe Handling Procedures: Procedure for the safe loading, transfer, and storage of ammonia.\n> Loading Limits: Clearly defined loading limits in accordance with the IGF Code.\n> Communication Procedure: Effective communication procedures between ship and shore personnel.\n> Equipment Compatibility: Verification of compatibility between shipboard and shorebased systems.\n6.8 Provisions on loading limit for fuel tanks\n> 6.8.1 Storage tanks for liquefied ammonia should not be filled to more than a volume equivalent to 98% full at the reference\ntemperature as defined in 2.2.36 of the IGF Code.\n> 6.8.2 In cases where the tank insulation and tank location make the probability very small for the tank contents to be\nheated up due to an external fire, special considerations may be made to allow a higher loading limit than calculated using\nthe reference temperature, but never above 95%.\n> (Class NK, 2024)\n> Bunkering procedures, and safety framework are to be developed with reference to the Ammonia Bunkering Management\nPlan (ABMP). Subsequent reviews and amendments in procedures are to be recorded in the ABMP.\n> (The Class NK 2025 Guidelines for the Safe Operation of Ammonia-Fuelled Vessels, Appendix 3)\nSafety Management System Updates for Ammonia Fuel Use\n> The company’s procedures should include fuel-specific operating procedures, maintenance requirements, and emergency\npreparedness measures, including regular drills. These procedures should specifically address residual risks that\ncannot be eliminated but must be mitigated through appropriate control measures. Formal risk assessments should be\nconducted to identify and address potential hazards associated with the use of ammonia as fuel. These assessments\nshould consider risks to personnel onboard, the environment, and the structural integrity of the vessel. Particular emphasis\nshould be placed on hazards related to the vessel’s physical design, layout, operation, and maintenance, including any\nreasonably foreseeable failures. Given the toxicity of ammonia and the potential for its release, thorough evaluation is\nessential to safeguard crew and environmental safety.\nScope of Risk assessment\nThe assessment should cover all relevant aspects of the vessel, focusing on system interactions and\navailable data. Key areas include:\n> Ammonia storage and vapor/pressure management systems\n> Venting and ventilation arrangements\n> Engine room and machinery spaces\n> Ammonia consumption equipment\n> Ammonia fuel supply and return systems\n> (ABS -Safety Insights For Ammonia as a Marine Fuel March 2025)\nRisk assessment\n> 4.2.1 A holistic risk assessment should be conducted to ensure that risks arising from the use of ammonia as fuel a􀆯ectin g\npersons on board, the environment, the structural strength, or the integrity of the ship and its sub-systems are addressed.\nConsideration should be given to the hazards associated with physical layout, operation and maintenance, following any\nreasonably foreseeable failure.\n> 4.2.2 The risk assessment should specifically consider the ammonia system integrity with a focus on its ability to prevent\nand isolate leakages and also evaluate potential toxicity hazards, ignition mechanisms and consequences of ignition.\nSpecial consideration should be given, but not limited to, the following specific ammonia-related hazards and topics:\n> 1- loss of function;\n> 2- component damage;\n> 3- fire;\n> 4- explosion;\n> 5- toxicity; and\n> 6- electric shock\n> 4.2.3 Risks, which cannot be eliminated, should be mitigated as necessary. Details of risks, and the means by\nwhich they are mitigated, should be documented to the satisfaction of the Administration.\n> (MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.2","internal_question_no":"07D.002","question_sort_key":7400200.177,"question_text":"Is the vessel provided with a ship-specific bilge management system to prevent fuel from ammonia consumers mixing with bilge water, and are the Master and officers familiar with the associated procedures?","guide_to_inspection":"> Bilge Management for Fuel-Contaminated Areas\n>\n> Where there is a risk of fuel mixing with bilge water from ammonia fuel consumers, dedicated bilge storage tanks should\nbe provided, separate from those used for general bilge collection.\n> This separation is essential to ensure safe bilge transfer operations, effective maintenance of bilge tanks, and proper\nonboard treatment of contaminated bilge water.\n> (Class NK 2024)\n> Procedures for bilge handling should be clearly documented and integrated into the vessel’s SMS. The Master and officers\nshould be trained in, and familiar with, these procedures. If alternative measures are implemented, they should provide an\nequivalent level of safety and operational effectiveness.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":102,"source_page_end":102,"raw_source_text":"Is the vessel provided with a ship-specific bilge management system to prevent fuel from ammonia consumers\nmixing with bilge water, and are the Master and officers familiar with the associated procedures? (V)\nGuide to Inspection\n> Bilge Management for Fuel-Contaminated Areas\n>\n> Where there is a risk of fuel mixing with bilge water from ammonia fuel consumers, dedicated bilge storage tanks should\nbe provided, separate from those used for general bilge collection.\n> This separation is essential to ensure safe bilge transfer operations, effective maintenance of bilge tanks, and proper\nonboard treatment of contaminated bilge water.\n> (Class NK 2024)\n> Procedures for bilge handling should be clearly documented and integrated into the vessel’s SMS. The Master and officers\nshould be trained in, and familiar with, these procedures. If alternative measures are implemented, they should provide an\nequivalent level of safety and operational effectiveness.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.3","internal_question_no":"07D.003","question_sort_key":7400300.178,"question_text":"Were the Master, engineering officers, and all personnel involved in the Ammonia bunkering operation adequately trained according to the relevant IMO and international and local regulation applicable to the area of operation?","guide_to_inspection":"19.2.2 The master, officers, ratings and other personnel on ships using ammonia fuel should have received training and be\nqualified in the use of gaseous fuel in accordance with the STCW Convention and the STCW Code, taking into account the\nspecific hazards of ammonia.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)\nConsidering the current regulatory gap in training requirements for seafarers handling ammonia as a marine fuel, RightShip\nrecommends the adoption of an interim training framework. Vessel managers are encouraged to consider the following\nguidance when developing training programs for Masters and Officers involved in ammonia bunkering operations, until formal\nrequirements are established by the IMO.\nSafe Bunkering and Handling of Ammonia as Marine Fuel\n> Understand the properties and hazards of ammonia as a marine fuel.\n> Operate and maintain ammonia-related systems safely and effectively.\n> Respond appropriately to emergencies involving ammonia.\n> Comply with relevant safety, environmental, and operational procedure.\nTraining Content:\n1. Introduction to Ammonia as a Marine Fuel\n> Role in maritime decarbonization\n> Benefits and challenges\n> Overview of current regulatory and gaps\n2. Chemical and Physical Properties of Ammonia\n> Toxicity, flammability, explosivity\n> Corrosiveness and material compatibility\n> Behavior under varying temperature and pressure\n3. Ammonia Fuel Systems and Equipment\n> Storage systems (pressurized, refrigerated, hybrid)\n> Transfer and bunkering systems\n> Instrumentation, control, and monitoring systems\n> Detection and alarm systems\n4. Safety and Hazard Management\n> Hazard identification and risk assessment\n> Control measures and safety barriers\n> Occupational health and safety protocols\n> Personal Protective Equipment (PPE): selection, use, and maintenance\n5. Operational Procedures\n> Pre-bunkering planning and checklists\n> Bunkering execution and monitoring\n> Fuel changeover procedures\n> Maintenance regimes for ammonia systems\n> Automation and remote operation considerations\n6. Emergency Response\n> Leak, spill, fire, and explosion scenarios\n> Emergency shutdown systems\n> Use of water curtains and containment measures\n> Crew coordination and communication protocols\n7. Environmental Protection\n> Spill prevention and containment\n> Pollution control technologies\n> Environmental compliance measures\n8. Legal and Regulatory Awareness\n> Overview of applicable international and national regulations\n> Classification society guidelines\n> Documentation and reporting requirements\n9. Practical Training and Simulation\n> Simulated bunkering and emergency scenarios\n> Use of PPE and emergency response tools","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":103,"source_page_end":103,"raw_source_text":"Were the Master, engineering officers, and all personnel involved in the Ammonia bunkering operation adequately\ntrained according to the relevant IMO and international and local regulation applicable to the area of operation? (V)\nGuide to Inspection\n19.2.2 The master, officers, ratings and other personnel on ships using ammonia fuel should have received training and be\nqualified in the use of gaseous fuel in accordance with the STCW Convention and the STCW Code, taking into account the\nspecific hazards of ammonia.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)\nConsidering the current regulatory gap in training requirements for seafarers handling ammonia as a marine fuel, RightShip\nrecommends the adoption of an interim training framework. Vessel managers are encouraged to consider the following\nguidance when developing training programs for Masters and Officers involved in ammonia bunkering operations, until formal\nrequirements are established by the IMO.\nSafe Bunkering and Handling of Ammonia as Marine Fuel\n> Understand the properties and hazards of ammonia as a marine fuel.\n> Operate and maintain ammonia-related systems safely and effectively.\n> Respond appropriately to emergencies involving ammonia.\n> Comply with relevant safety, environmental, and operational procedure.\nTraining Content:\n1. Introduction to Ammonia as a Marine Fuel\n> Role in maritime decarbonization\n> Benefits and challenges\n> Overview of current regulatory and gaps\n2. Chemical and Physical Properties of Ammonia\n> Toxicity, flammability, explosivity\n> Corrosiveness and material compatibility\n> Behavior under varying temperature and pressure\n3. Ammonia Fuel Systems and Equipment\n> Storage systems (pressurized, refrigerated, hybrid)\n> Transfer and bunkering systems\n> Instrumentation, control, and monitoring systems\n> Detection and alarm systems\n4. Safety and Hazard Management\n> Hazard identification and risk assessment\n> Control measures and safety barriers\n> Occupational health and safety protocols\n> Personal Protective Equipment (PPE): selection, use, and maintenance\n5. Operational Procedures\n> Pre-bunkering planning and checklists\n> Bunkering execution and monitoring\n> Fuel changeover procedures\n> Maintenance regimes for ammonia systems\n> Automation and remote operation considerations\n6. Emergency Response\n> Leak, spill, fire, and explosion scenarios\n> Emergency shutdown systems\n> Use of water curtains and containment measures\n> Crew coordination and communication protocols\n7. Environmental Protection\n> Spill prevention and containment\n> Pollution control technologies\n> Environmental compliance measures\n8. Legal and Regulatory Awareness\n> Overview of applicable international and national regulations\n> Classification society guidelines\n> Documentation and reporting requirements\n9. Practical Training and Simulation\n> Simulated bunkering and emergency scenarios\n> Use of PPE and emergency response tools","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.4","internal_question_no":"07D.004","question_sort_key":7400400.179,"question_text":"Does the vessel have an appropriate emergency response plan, are crew members familiar with their emergency duties, and are emergency drills conducted as required?","guide_to_inspection":"20.2 Functional requirements\n20.2.1 This chapter relates to functional requirements in 3.2.1, 3.2.12 and 3.2.16.\nIn particular the following apply:\n1. for the protection of crew members who are engaged in operations, maintenance of ammonia fuel systems, and emergency\nresponse, the ship should have on board protective equipment suitable for ammonia exposure, taking the exposure risk of\ndifferent operations into account;\n2. for the protection and treatment of crew members affected by ammonia leakages, the ship should have on board suitable\nemergency equipment; and\n3. suitable respiratory and eye protection for emergency escape purposes should be provided for every person on board.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":104,"source_page_end":104,"raw_source_text":"Does the vessel have an appropriate emergency response plan, are crew members familiar with their emergency\nduties, and are emergency drills conducted as required? (V)\nGuide to Inspection\n20.2 Functional requirements\n20.2.1 This chapter relates to functional requirements in 3.2.1, 3.2.12 and 3.2.16.\nIn particular the following apply:\n1. for the protection of crew members who are engaged in operations, maintenance of ammonia fuel systems, and emergency\nresponse, the ship should have on board protective equipment suitable for ammonia exposure, taking the exposure risk of\ndifferent operations into account;\n2. for the protection and treatment of crew members affected by ammonia leakages, the ship should have on board suitable\nemergency equipment; and\n3. suitable respiratory and eye protection for emergency escape purposes should be provided for every person on board.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.5","internal_question_no":"07D.005","question_sort_key":7400500.18,"question_text":"Are the crew aware of the locations and operation of the decontamination showers and eyewash, and are the showers in good operational order in suitably marked locations?","guide_to_inspection":"The showers and eyewashes should be operable in all ambient conditions. A heating system with temperature control is\nrequired if pipe routing of the water supply exposes the piping to freezing conditions. Water supply capacity should be sufficient\nfor simultaneous use of at least two units. Thermal insulation is not considered as an alternative to a system with temperature\ncontrol.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":104,"source_page_end":104,"raw_source_text":"Are the crew aware of the locations and operation of the decontamination showers and eyewash, and are the\nshowers in good operational order in suitably marked locations? (V)\nGuide to Inspection\nThe showers and eyewashes should be operable in all ambient conditions. A heating system with temperature control is\nrequired if pipe routing of the water supply exposes the piping to freezing conditions. Water supply capacity should be sufficient\nfor simultaneous use of at least two units. Thermal insulation is not considered as an alternative to a system with temperature\ncontrol.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.6","internal_question_no":"07D.006","question_sort_key":7400600.181,"question_text":"Are officers and ratings aware of the locations of emergency stops and are these in good working order with recorded evidence of regular testing?","guide_to_inspection":"Compressors, pumps and fuel supply should be arranged for manual remote emergency stop from the following locations as\napplicable:\n> navigation bridge;\n> cargo control room;\n> onboard safety center;\n> engine control room;\n> fire-control station; and\n> adjacent to the exit of fuel preparation rooms.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":104,"source_page_end":104,"raw_source_text":"Are officers and ratings aware of the locations of emergency stops and are these in good working order with\nrecorded evidence of regular testing? (V)\nGuide to Inspection\nCompressors, pumps and fuel supply should be arranged for manual remote emergency stop from the following locations as\napplicable:\n> navigation bridge;\n> cargo control room;\n> onboard safety center;\n> engine control room;\n> fire-control station; and\n> adjacent to the exit of fuel preparation rooms.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.7","internal_question_no":"07D.007","question_sort_key":7400700.182,"question_text":"Is the vessel equipped with a Safe Haven that has sufficient capacity to accommodate all personnel, located and designed in accordance with safety requirements to prevent ammonia exposure, and are regular drills conducted to ensure crew readiness in the event of an ammonia release?","guide_to_inspection":"A Safe Haven should be provided on board to offer refuge in the event of an ammonia release. The\nfollowing requirements apply:\n> The Safe Haven should consist of one or more enclosed spaces with a combined capacity sufficient to accommodate all\npersons on board.\n> It should be located at essential operational areas of the vessel and designed to minimize the risk of ammonia exposure.\nThis can be achieved through:\n> Dedicated ventilation systems, or\n> Self-sustaining air supply systems.\n> Enclosed toxic areas should not be adjacent to accommodation spaces, service areas, electrical equipment rooms, or\ncontrol stations. “Adjacent” includes facial, linear, or point contact.\n> Air intakes for the Safe Haven should be equipped with:\n> Ammonia detectors, and\n> Internal closing devices to seal the space when ammonia is detected.\n> If closing the air intakes poses a risk of suffocation, additional measures should be in place to:\n> Prevent ammonia inflow, or\n> Provide oxygen or breathable air to occupants.\n> Regular drills should be conducted to ensure crew members are familiar with Safe Haven procedures and can respond\neffectively in an emergency.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":105,"source_page_end":105,"raw_source_text":"Is the vessel equipped with a Safe Haven that has sufficient capacity to accommodate all personnel, located\nand designed in accordance with safety requirements to prevent ammonia exposure, and are regular drills\nconducted to ensure crew readiness in the event of an ammonia release? (V)\nGuide to Inspection\nA Safe Haven should be provided on board to offer refuge in the event of an ammonia release. The\nfollowing requirements apply:\n> The Safe Haven should consist of one or more enclosed spaces with a combined capacity sufficient to accommodate all\npersons on board.\n> It should be located at essential operational areas of the vessel and designed to minimize the risk of ammonia exposure.\nThis can be achieved through:\n> Dedicated ventilation systems, or\n> Self-sustaining air supply systems.\n> Enclosed toxic areas should not be adjacent to accommodation spaces, service areas, electrical equipment rooms, or\ncontrol stations. “Adjacent” includes facial, linear, or point contact.\n> Air intakes for the Safe Haven should be equipped with:\n> Ammonia detectors, and\n> Internal closing devices to seal the space when ammonia is detected.\n> If closing the air intakes poses a risk of suffocation, additional measures should be in place to:\n> Prevent ammonia inflow, or\n> Provide oxygen or breathable air to occupants.\n> Regular drills should be conducted to ensure crew members are familiar with Safe Haven procedures and can respond\neffectively in an emergency.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.8","internal_question_no":"07D.008","question_sort_key":7400800.183,"question_text":"Are the Master and officers, familiar with the procedure for safe entry into the fuel preparation room, including the maintenance and regular testing of the ammonia release mitigation system?","guide_to_inspection":"Safe Entry Procedure for Ammonia Fuel Preparation Room\nSafe entry into an ammonia fuel preparation room requires a structured, multi-step procedure that prioritises ventilation, PPE,\nand emergency preparedness:\n> The room should be thoroughly ventilated prior to entry to eliminate any potential buildup of ammonia gas.\n> Personnel should wear appropriate PPE, including self-contained breathing apparatus (SCBA) and gas-tight protective\nsuits.\n> A clearly defined emergency response plan should be in place, including designated escape routes and readily accessible\nsafety equipment.\nAll personnel involved should be familiar with and trained in the emergency procedures.\nRegular reviews and drills should be conducted to ensure ongoing compliance and readiness.\n(China Classification Society -Key Points for Practical Application of Ammonia-fuelled Vessels 2025)\nProvisions for fuel preparation rooms\n5.7.1.2 When fuel preparation rooms cannot be located on open deck, or accessed from open deck, access should be provided\nthrough an airlock in compliance with 5.11.\n5.7.1.3 Fuel preparation rooms should be designed to safely contain fuel leakages. The fuel preparation room boundaries should\nbe gastight towards other spaces in the ship.\n5.7.1.6 The fuel preparation room should be fitted with ventilation arrangements ensuring that the space can withstand any\npressure build-up caused by vaporization of the liquefied fuel.\n5.7.1.8 Fuel preparation room entrances should be arranged with water screens having constantly available water supply. The\nwater screen should be possible to activate from a safe location outside the toxic fuel preparation room if an ammonia leak\noccurs. The water screens should be arranged on the outside of the fuel preparation room. The arrangement should include the\nmeans to safely manage any ammonia effluent produced in their operation.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":105,"source_page_end":105,"raw_source_text":"Are the Master and officers, familiar with the procedure for safe entry into the fuel preparation room,\nincluding the maintenance and regular testing of the ammonia release mitigation system? (V)\nGuide to Inspection\nSafe Entry Procedure for Ammonia Fuel Preparation Room\nSafe entry into an ammonia fuel preparation room requires a structured, multi-step procedure that prioritises ventilation, PPE,\nand emergency preparedness:\n> The room should be thoroughly ventilated prior to entry to eliminate any potential buildup of ammonia gas.\n> Personnel should wear appropriate PPE, including self-contained breathing apparatus (SCBA) and gas-tight protective\nsuits.\n> A clearly defined emergency response plan should be in place, including designated escape routes and readily accessible\nsafety equipment.\nAll personnel involved should be familiar with and trained in the emergency procedures.\nRegular reviews and drills should be conducted to ensure ongoing compliance and readiness.\n(China Classification Society -Key Points for Practical Application of Ammonia-fuelled Vessels 2025)\nProvisions for fuel preparation rooms\n5.7.1.2 When fuel preparation rooms cannot be located on open deck, or accessed from open deck, access should be provided\nthrough an airlock in compliance with 5.11.\n5.7.1.3 Fuel preparation rooms should be designed to safely contain fuel leakages. The fuel preparation room boundaries should\nbe gastight towards other spaces in the ship.\n5.7.1.6 The fuel preparation room should be fitted with ventilation arrangements ensuring that the space can withstand any\npressure build-up caused by vaporization of the liquefied fuel.\n5.7.1.8 Fuel preparation room entrances should be arranged with water screens having constantly available water supply. The\nwater screen should be possible to activate from a safe location outside the toxic fuel preparation room if an ammonia leak\noccurs. The water screens should be arranged on the outside of the fuel preparation room. The arrangement should include the\nmeans to safely manage any ammonia effluent produced in their operation.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07D","section_number":7,"section_letter":"D","section_title":"Fuel Management (Alternative Fuel- Ammonia)","printed_question_no":"7.9","internal_question_no":"07D.009","question_sort_key":7400900.184,"question_text":"Are muster stations and access points for life jackets and immersion suits located outside all designated hazardous and toxic areas?","guide_to_inspection":"On ammonia-fuelled vessels, RightShip defines hazardous areas as locations where there is a credible risk of ammonia leaks or\nspills. These typically include fuel storage compartments, fuel preparation rooms, and areas surrounding fuel lines, valves, and\nassociated equipment. Given the toxic and corrosive nature of ammonia, these zones must be clearly identified and equipped\nwith appropriate safety controls to prevent leaks and minimise the risk of personnel exposure.\nToxic area means an area in which ammonia is or may be expected to be present.\nToxic space means an enclosed or semi-enclosed space in which ammonia is or may be expected to be present. A gas-safe\nmachinery space is not considered to be a toxic space.\nMustering stations and life-saving equipment, and access to such stations and equipment, should not be located in toxic areas\nas specified in Gas Dispersion Plan.\nToxic areas and spaces are defined to allow for a safe arrangement preventing cross-contamination from ammonia releases,\nand to facilitate safe arrangement of life-saving appliances, emergency escapes, air intakes, outlets and other openings into the\naccommodation, service and machinery spaces, control stations and other non-toxic spaces.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":106,"source_page_end":106,"raw_source_text":"Are muster stations and access points for life jackets and immersion suits located outside all designated\nhazardous and toxic areas? (V)\nGuide to Inspection\nOn ammonia-fuelled vessels, RightShip defines hazardous areas as locations where there is a credible risk of ammonia leaks or\nspills. These typically include fuel storage compartments, fuel preparation rooms, and areas surrounding fuel lines, valves, and\nassociated equipment. Given the toxic and corrosive nature of ammonia, these zones must be clearly identified and equipped\nwith appropriate safety controls to prevent leaks and minimise the risk of personnel exposure.\nToxic area means an area in which ammonia is or may be expected to be present.\nToxic space means an enclosed or semi-enclosed space in which ammonia is or may be expected to be present. A gas-safe\nmachinery space is not considered to be a toxic space.\nMustering stations and life-saving equipment, and access to such stations and equipment, should not be located in toxic areas\nas specified in Gas Dispersion Plan.\nToxic areas and spaces are defined to allow for a safe arrangement preventing cross-contamination from ammonia releases,\nand to facilitate safe arrangement of life-saving appliances, emergency escapes, air intakes, outlets and other openings into the\naccommodation, service and machinery spaces, control stations and other non-toxic spaces.\n(MSC.1-Circ.1687, Interim Guidelines For the safety of Ships Using Ammonia as Fuel 2025)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ61$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 6/15 imported.' AS result,
  '07B.005' AS chunk_first_question,
  '07D.009' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
